import React, { useState, useEffect } from "react";
import { OutlinedInput, InputLabel, MenuItem, Select, FormControl, Container } from "@mui/material";



export default function Marketing({onChange,value}) {
  const [selectedNames, setSelectedNames] = useState(value);



  useEffect(() => {
    onChange("marketing",selectedNames );
  }, [selectedNames])
  

  



  return (
    <>
        <FormControl sx={{width:"100%", mb:1 }}>
        <InputLabel> Marketing </InputLabel>
        <Select
            onChange={(e) => setSelectedNames(e.target.value)}
            value={selectedNames}
            input={<OutlinedInput label="Multiple Select"  fullWidth/>}
            fullWidth
        >
            <MenuItem value={"medical"}> Medicale </MenuItem>
            <MenuItem value={"commercial"}> Commerciale </MenuItem>
            <MenuItem value={"medicocommercial"}> Medicocommerciale </MenuItem>
        </Select>
        </FormControl>
    </>
  );
}