import React, { useEffect, useState } from 'react'
import axios from 'axios'


export default function UseCProducts(product) {
    const [cproducts, setcproducts] = useState([])
    const [cloading, setloading] = useState(false)

    const get_products=()=>{
        setloading(true) 
        axios({
            url:"https://app.liliumpharma.com/concurents/products/api/"+product,
        })
        .then(res=>setcproducts(res.data))
        .catch(err=>console.log())
        .finally(()=>setloading(false))
    }

    useEffect(()=>{
        product && get_products()
    },[product])

  return {cproducts, cloading }
}
