import  { useState, useEffect } from 'react'
import "./App.css"
import UseProducts from './hooks/UseProducts'
import ProductSelector from './components/product/ProductSelector';
import ProductDetails from './components/product/ProductDetails';
import { ThemeProvider, createTheme } from '@mui/material/styles';
import { green, purple } from '@mui/material/colors';
import UseCProducts from './hooks/UseCProducts';
import List from './components/cproduct/List';
import CProductForm from './components/cproduct/form/CProductForm';
import AddIcon from '@mui/icons-material/Add';
import Fab from '@mui/material/Fab';


const theme = createTheme({
  palette: {
    primary: {
      main: "#32CD32",
    },
    secondary: {
      main: green[500],
    },
  },
});


export default function App() {
  const {products, loading }=UseProducts();
  const [product, setproduct] = useState()
  const {cproducts, cloading }=UseCProducts(product ? product.id : undefined);

  const [cproduct, setcproduct] = useState()


  const [open, setopen] = useState(false);



  
  
  return (
    <>
      <ThemeProvider theme={theme}>
            {products.length > 0  && 
            <>
                <ProductSelector products={products} onChange={(p)=>setproduct(p)}/>
                {product && <ProductDetails product={product} />}
                {cproducts.length > 0 && <List cproducts={cproducts} open={open} setopen={setopen} setcproduct={setcproduct} />}
                {product &&  <CProductForm  open={open} setopen={setopen} produit={product.id} cproduct={cproduct} key={open}/> }

                <Fab size="medium"   sx={{...fabStyle}} onClick={()=>{ setcproduct();setopen(true) } }>
                    <AddIcon  sx={{color:"#fff"}}/>     
                </Fab>


            </>
            }
      </ThemeProvider>
      
    </>
    )
}

const fabStyle = {
  position: 'fixed',
  bottom: 25,
  right: 16,
  background:"#32CD32"
};
