import { Box, Container, Typography } from '@mui/material'
import React from 'react'
import VerifiedUserIcon from '@mui/icons-material/VerifiedUser';
import EditIcon from '@mui/icons-material/Edit';
import styled from 'styled-components';


export default function SingleCProduct({product,setopen, setcproduct}) {
  return (
    <Box sx={{p:1, border:"1px solid rgba(0,0,0,.2)", minWidth:"87vw"}}>
      <Container>
          <ProductImageContainer>
            <ProductImage src={product.image}/>
          </ProductImageContainer>

          <Container sx={{py:1,  border:"1px solid rgba(0,0,0,.2)", my:1, position:"relative" }}>
            <Typography> <b>name:</b> {product.name} </Typography>
            <Typography> <b>company:</b> {product.company} </Typography>
            <Typography> <b>marketing:</b> {product.marketing} </Typography>
            <Typography> <b>country:</b> {product.country} </Typography>
            <Typography> <b>treatment duration:</b> {product.treatment_duration} </Typography>
            <Typography> <b>price:</b> {product.price} DA </Typography>
            <Typography> <b>strength point:</b> {product.good} </Typography>
            <Typography> <b>weak point:</b> {product.bad} </Typography>
            <Typography> <b>compositions:</b>  
              {product.components.map(c=>
                  <small key={c.id}> {c.name} {c.qtt},</small>
                )}
            </Typography>
          <Box sx={{position:"absolute", top:4, right:4, }}>
            { product.valid ?
               <VerifiedUserIcon color="primary" sx={{fontSize:30}} /> 
               :
               <EditIcon sx={{fontSize:30}}  onClick={()=>{setcproduct(product);setopen(true)}} /> 
              }    
          </Box>
          </Container>

      </Container>
    </Box>
  )
}


const ProductImageContainer=styled.div`
  display: flex;
  /* align-items: center; */
  justify-content: center;
`
const ProductImage=styled.img`
  max-height: 300px;
  max-width: 100%;
`