import { Box, Container, FormControl, Modal, TextField, Typography } from "@mui/material"
import { useState } from "react"
import Components from "./Components";
import LoadingButton from '@mui/lab/LoadingButton';
import SaveIcon from '@mui/icons-material/Save';
import axios from "axios";
import Marketing from "./Marketing";
import { TextareaAutosize } from '@mui/base/TextareaAutosize';
import Shape from "./Shape";



export default function CProductForm({produit, open, setopen, cproduct}) {


    const [product, setproduct] = useState(cproduct ? cproduct : {product:produit,components:[]})

    const set_product=(name, value)=>setproduct({...product,[name]:value})




    const isFile = input => 'File' in window && input instanceof File;

    
    const send=()=>{

        // console.log(product)
        const formData = new FormData();

        if(isFile(product.image))
            formData.append("image", product.image) 
    
        if(isFile(product.image_2))
            formData.append("image_2", product.image_2) 

        if(isFile(product.image_3))
            formData.append("image_3", product.image_3) 

        if(isFile(product.brochure))
            formData.append("brochure", product.brochure) 


            
        formData.append("name", product.name) 
        formData.append("company", product.company) 
        formData.append("country", product.country) 
        formData.append("price", product.price) 
        formData.append("treatment_duration", product.treatment_duration) 
        formData.append("components", product.components) 
        formData.append("marketing", product.marketing ) 
        formData.append("components", JSON.stringify (product.components) ) 
        formData.append("good", product.good) 
        formData.append("bad", product.bad) 
        formData.append("observations", product.observations) 
        formData.append("product", product.product) 
        formData.append("shape", product.shape) 


        // console.log
        axios({
            url:`https://app.liliumpharma.com/concurents/api/${cproduct ? cproduct.id : ""}`,
            method:cproduct ? "PUT" : "POST",
            data:formData
        })
        .then(res=>{
            console.log(res)
            window.location.reload()
        })
        .catch(err=>{
            console.error(err)
            alert("veuillez verifier le formulaire")
        })

    }



  return (
    <>
        <Modal
            open={open}
            onClose={() => setopen(false)}
            aria-labelledby="modal-modal-form"
            aria-describedby="modal-modal-description"
            sx={{p:3}}
            >
            <Container sx={{background:"#fff", py:3, maxHeight:"95vh", overflow:"scroll"}}>

                <Typography id="modal-modal-title" variant="h6" component="h2" sx={{mb:2}}>
                        Ajouter un  concurrent
                </Typography>


                    <TextField
                            sx={{ mb:2}}
                            required
                            fullWidth
                            name="name"
                            label="Nom"
                            onChange={(e)=>set_product("name",e.target.value)}
                            defaultValue={product.name}
                    />
                    <TextField
                            sx={{ mb:2}}
                            required
                            fullWidth
                            name="company"
                            label="company"
                            onChange={(e)=>set_product("company",e.target.value)}
                            defaultValue={product.company}
                    />
                    <TextField
                            sx={{ mb:2}}
                            required
                            fullWidth
                            name="country"
                            label="country"
                            onChange={(e)=>set_product("country",e.target.value)}
                            defaultValue={product.country}
                    />
                    <Marketing  onChange={set_product} value={product.marketing}/>
                    <Shape  onChange={set_product} value={product.shape}/>
                    <TextField
                            sx={{ mb:2}}
                            required
                            fullWidth
                            name="price"
                            label="price"
                            onChange={(e)=>set_product("price",e.target.value)}
                            defaultValue={product.price}
                    />
                    <TextField
                            sx={{ mb:2}}
                            required
                            fullWidth
                            name="treatment_duration"
                            label="treatment_duration"
                            onChange={(e)=>set_product("treatment_duration",e.target.value)}
                            defaultValue={product.treatment_duration}
                    />
                    
                    <Components product={product} setproduct={setproduct} />


                    <Box sx={{mb:2}}>   
                        <label>Image:</label>
                        <input
                            type="file"
                            accept="image/*"
                            placeholder={product.image}
                            onChange={(e) => set_product("image",e.target.files[0])}

                            />
                    </Box>
                    <Box sx={{mb:2}}>   
                        <label>Image2:</label>
                        <input
                            type="file"
                            accept="image/*"
                            // placeholder={_Repport.image}
                            onChange={(e) => set_product("image_2",e.target.files[0])}
                            placeholder={product.image_2}
                            />
                    </Box>
                    <Box sx={{mb:2}}>   
                        <label>Image3:</label>
                        <input
                            type="file"
                            accept="image/*"
                            // placeholder={_Repport.image}
                            onChange={(e) => set_product("image_3",e.target.files[0])}
                            placeholder={product.image_3}
                            />
                    </Box>
                    <Box sx={{mb:2}}>   
                        <label>brochure:</label>
                        <input
                            type="file"
                            accept="image/*"
                            // placeholder={_Repport.image}
                            onChange={(e) => set_product("brochure",e.target.files[0])}
                            placeholder={product.brochure}
                            />
                    </Box>

                        

                    <FormControl fullWidth>
                        Weak point
                        <TextareaAutosize 
                            minRows={3}
                            label="Observation"
                            onChange={(e)=>set_product("bad",e.target.value)}
                            style={{padding:7,borderRadius:5,border:"1px solid rgba(0,0,0,.2)",marginBlock:7}}
                            defaultValue={product.bad}
                        />
                    </FormControl>
                    <FormControl fullWidth>
                        Force Point
                        <TextareaAutosize 
                            minRows={3}
                            label="Observation"
                            onChange={(e)=>set_product("good",e.target.value)}
                            style={{padding:7,borderRadius:5,border:"1px solid rgba(0,0,0,.2)",marginBlock:7}}
                            defaultValue={product.good}
                        />
                    </FormControl>
                    <FormControl fullWidth>
                        Observation
                        <TextareaAutosize 
                            minRows={3}
                            label="Observation"
                            onChange={(e)=>set_product("observations",e.target.value)}
                            style={{padding:7,borderRadius:5,border:"1px solid rgba(0,0,0,.2)",marginBlock:7}}
                            defaultValue={product.observations}
                        />
                    </FormControl>


                    

                    <LoadingButton
                        variant="contained" 
                        sx={{my:2, py:1, width:"100%", fontSize:20 }}
                        loading={false}
                        loadingPosition="start"
                        startIcon={<SaveIcon />}
                        onClick={()=>send()}
                    >
                            Sauvgarder
                    </LoadingButton>



            </Container>
        </Modal>
    </>
  )
}
